export type RepeatType = 'none' | 'daily' | 'weekly' | 'monthly' | 'yearly' | 'custom'

export interface Task {
  id: string
  title: string
  description?: string
  dueDate?: string       // ISO date string
  dueTime?: string       // 'HH:mm'
  duration?: { start: string; end: string } // 'HH:mm'
  priority: Priority
  completed: boolean
  completedAt?: string
  notification?: string  // minutes before
  repeat: RepeatType
  repeatDays?: number[]  // days of week
  repeatCustom?: {
    interval: number
    unit: 'week' | 'month'
    weekdays?: number[]
    monthDay?: number
  }
  attachment?: {
    name: string
    mimeType: string
    dataUrl: string
  }
  imageUrl?: string
  listId?: string
  matrixBlock?: 'urgent-important' | 'not-urgent-important' | 'urgent-not-important' | 'not-urgent-not-important'
  createdAt: string
}

export interface User {
  id: string
  email: string
  name: string
  avatar?: string
  isPremium: boolean
  premiumExpiresAt?: string
}

