  duration: number       // minutes
  shortBreak: number
  longBreak: number
  sessionsUntilLong: number
  sound: string
  workingSound?: string
  showOnLockScreen: boolean
}

export interface AppSettings {
  language: string
  theme: string
  visibleGroups: string[]
