  id: number
  email: string
  first_name: string
  last_name: string
  avatar: string | null
}

interface LoginResponse {
  tokens: {
    access: string
    refresh: string
  }
}

interface RegisterResponse extends LoginResponse {
  user: BackendUser
}

interface GoogleLoginPayload {
  firebase_token: string
}

interface GoogleLoginResponse extends RegisterResponse {}
